using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type".
        // Preserve old property name so existing documents are still found.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 2: Id format changed from "EntityType|Key" to just "Key".
        // Preserve old "Blog|{Id}" format so existing documents keep the same id.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .ToJsonProperty("id")
            .HasValueGenerator<BlogIdValueGenerator>();

        // Breaking change 3: HasIndex is not supported on Cosmos DB and now throws.
        // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}

// Value generator that preserves the legacy "Blog|{key}" id format
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;
class BlogIdValueGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry) => $"Blog|{Guid.NewGuid()}";
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

