class SyncJob
{
    void Run(BlogContext context)
    {
        // Breaking change 4: Sync I/O now throws by default. Use async methods.
        var blogs = context.Blogs.ToListAsync().GetAwaiter().GetResult();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        context.SaveChangesAsync().GetAwaiter().GetResult();
    }

    // Preferred: use fully async pattern
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }
}

